1	// WORKSTATE handoff integrity harness.
2	// Checks that the current handoff record is backed by real files, hashes, and completion artifacts.
3	// --workstate + --applier-log 둘 다 지정 시 fixture 격리 모드: reconciliation+malformed+blockers만 실행.
4	using System.Security.Cryptography;
5	using System.Text.Encodings.Web;
6	using System.Text.Json;
7	using System.Text.Json.Nodes;
8	
9	internal static class HandoffIntegrityCli
10	{
11	    private static readonly JsonSerializerOptions JsonOptions = new()
12	    {
13	        WriteIndented = true,
14	        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
15	    };
16	
17	    private static readonly HashSet<string> DoneStatuses = new(StringComparer.OrdinalIgnoreCase)
18	    {
19	        "done", "completed", "complete", "pass", "passed",
20	    };
21	
22	    // handoff-integrity entry. exit 0=integrity verified, 1=contract gap, 2=harness error.
23	    internal static int Run(string[] args)
24	    {
25	        try
26	        {
27	            if (args.Any(a => string.Equals(a, "--pending-transition", StringComparison.OrdinalIgnoreCase)))
28	            {
29	                Console.Error.WriteLine("{\"error\":\"pending-not-allowed-on-cli\",\"code\":\"pending-not-allowed-on-cli\"}");
30	                return 1;
31	            }
32	            var root = GitTools.FindRepoRoot();
33	            var (workstatePath, applierLogPath, fixtureMode) = ParsePaths(args, root);
34	            if (!File.Exists(workstatePath))
35	                { Console.Error.WriteLine("{\"error\":\"WORKSTATE.json not found\"}"); return 2; }
36	            var parsed = JsonNode.Parse(File.ReadAllText(workstatePath)) as JsonObject;
37	            if (parsed is null)
38	                { Console.Error.WriteLine("{\"error\":\"WORKSTATE.json is not a JSON object\"}"); return 2; }
39	            return RunChecks(root, parsed, workstatePath, applierLogPath, fixtureMode);
40	        }
41	        catch (Exception ex)
42	        {
43	            Console.Error.WriteLine($"{{\"error\":\"handoff-integrity failed: {ex.Message}\"}}");
44	            return 2;
45	        }
46	    }
47	
48	    // --workstate / --applier-log 인자를 파싱해 절대 경로와 모드를 반환한다.
49	    private static (string workstatePath, string applierLogPath, bool fixtureMode) ParsePaths(string[] args, string root)
50	    {
51	        string? workstateArg = null;
52	        string? applierLogArg = null;
53	        for (int i = 1; i < args.Length; i++)
54	        {
55	            if (string.Equals(args[i], "--workstate", StringComparison.OrdinalIgnoreCase) && i + 1 < args.Length)
56	                workstateArg = args[++i];
57	            else if (string.Equals(args[i], "--applier-log", StringComparison.OrdinalIgnoreCase) && i + 1 < args.Length)
58	                applierLogArg = args[++i];
59	            else if (workstateArg is null && !args[i].StartsWith("--"))
60	                workstateArg = args[i];
61	        }
62	        var wsPath = workstateArg is not null
63	            ? Path.GetFullPath(Path.IsPathRooted(workstateArg) ? workstateArg : Path.Combine(root, workstateArg))
64	            : Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
65	        var logPath = applierLogArg is not null
66	            ? Path.GetFullPath(Path.IsPathRooted(applierLogArg) ? applierLogArg : Path.Combine(root, applierLogArg))
67	            : Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
68	        return (wsPath, logPath, applierLogArg is not null);
69	    }
70	
71	    // 모든 검사를 실행하고 보고서를 출력한다.
72	    private static int RunChecks(
73	        string root, JsonObject parsed, string workstatePath, string applierLogPath, bool fixtureMode)
74	    {
75	        var failures = new JsonArray();
76	        var warnings = new JsonArray();
77	        var changedFiles = new JsonArray();
78	        var diId = ReadString(parsed, "diId");
79	        var status = ReadString(parsed, "status");
80	
81	        var reconc = RunReconciliation(workstatePath, applierLogPath, failures, warnings);
82	        if (reconc.harnessErrors > 0)
83	        {
84	            Console.WriteLine(new JsonObject
85	            {
86	                ["harness"] = "handoff-integrity",
87	                ["workstate"] = Path.GetRelativePath(root, workstatePath).Replace('\\', '/'),
88	                ["fixtureMode"] = fixtureMode,
89	                ["verdict"] = "HARNESS_ERROR",
90	                ["failures"] = failures, ["warnings"] = warnings,
91	            }.ToJsonString(JsonOptions));
92	            return 2;
93	        }
94	
95	        if (!fixtureMode)
96	            RunFullModeChecks(root, parsed, diId, status, failures, warnings, changedFiles);
97	        CheckBlockerConsistency(parsed, status, failures);
98	
99	        Console.WriteLine(new JsonObject
100	        {
101	            ["harness"] = "handoff-integrity",
102	            ["workstate"] = Path.GetRelativePath(root, workstatePath).Replace('\\', '/'),
103	            ["applierLog"] = Path.GetRelativePath(root, applierLogPath).Replace('\\', '/'),
104	            ["fixtureMode"] = fixtureMode,
105	            ["diId"] = diId, ["status"] = status,
106	            ["changedFileCount"] = changedFiles.Count,
107	            ["failureCount"] = failures.Count, ["warningCount"] = warnings.Count,
108	            ["verdict"] = failures.Count == 0 ? "PASS" : "FAIL",
109	            ["reconciliation"] = reconc.reconciliationResult,
110	            ["changedFiles"] = changedFiles, ["failures"] = failures, ["warnings"] = warnings,
111	            ["note"] = fixtureMode
112	                ? "Fixture isolation mode: reconciliation+blockers only."
113	                : "Full mode: changedFiles hash, completion, queue, reconciliation.",
114	        }.ToJsonString(JsonOptions));
115	        return failures.Count == 0 ? 0 : 1;
116	    }
117	
118	    // full 모드에서 changedFiles·completion·queue를 검사한다.
119	    private static void RunFullModeChecks(
120	        string root, JsonObject parsed, string diId, string status,
121	        JsonArray failures, JsonArray warnings, JsonArray changedFiles)
122	    {
123	        CheckRequired(parsed, "schemaVersion", failures);
124	        CheckRequired(parsed, "diId", failures);
125	        CheckRequired(parsed, "status", failures);
126	        var changed = parsed["changedFiles"] as JsonArray;
127	        if (changed is null || changed.Count == 0)
128	            failures.Add(Failure("changedFiles", "missing", "changedFiles must be a non-empty array"));
129	        else
130	            foreach (var item in changed.OfType<JsonObject>())
131	                changedFiles.Add(CheckChangedFile(root, item, failures));
132	        CheckCompletionArtifacts(root, parsed, diId, status, failures, warnings);
133	        CheckQueueStatus(root, diId, status, failures, warnings);
134	    }
135	
136	    // HandoffIntegrityChecker를 실행하고 결과를 failures/warnings에 병합한다.
137	    private static (int harnessErrors, JsonNode? reconciliationResult) RunReconciliation(
138	        string workstatePath, string applierLogPath,
139	        JsonArray failures, JsonArray warnings)
140	    {
141	        var opts = new ReconciliationOptions(workstatePath, applierLogPath, null);
142	        var result = HandoffIntegrityChecker.Run(opts);
143	
144	        foreach (var e in result.HarnessErrors)
145	            Console.Error.WriteLine($"{{\"harness-error\":\"{e.Code}\",\"subject\":\"{e.Subject}\",\"message\":\"{e.Message}\"}}");
146	
147	        if (result.HarnessErrors.Count > 0)
148	            return (result.HarnessErrors.Count, null);
149	
150	        foreach (var f in result.Failures)
151	            failures.Add(Failure(f.Subject, f.Code, f.Message));
152	        foreach (var w in result.Warnings)
153	            warnings.Add(Warning(w.Subject, w.Code, w.Message));
154	
155	        JsonNode? metricsNode = null;
156	        if (result.Metrics is { } m)
157	        {
158	            metricsNode = new JsonObject
159	            {
160	                ["appliedTransitionCount"] = m.AppliedTransitionCount,
161	                ["successfulLogEntryCount"] = m.SuccessfulLogEntryCount,
162	                ["successfulLogIdCount"] = m.SuccessfulLogIdCount,
163	                ["duplicateSuccessLogCount"] = m.DuplicateSuccessLogCount,
164	                ["pendingExemptionApplied"] = m.PendingExemptionApplied,
165	                ["reconciliation"] = m.Reconciliation,
166	            };
167	        }
168	
169	        return (0, metricsNode);
170	    }
171	
172	    // 필수 최상위 WORKSTATE 필드를 확인한다.
173	    private static void CheckRequired(JsonObject root, string property, JsonArray failures)
174	    {
175	        if (root[property] is null || string.IsNullOrWhiteSpace(root[property]?.ToString()))
176	            failures.Add(Failure($"workstate.{property}", "missing", "required field is absent or empty"));
177	    }
178	
179	    // changedFiles 항목 하나를 파일시스템·해시와 대조한다.
180	    private static JsonObject CheckChangedFile(string root, JsonObject item, JsonArray failures)
181	    {
182	        var path = ReadString(item, "path");
183	        var entry = new JsonObject
184	        {
185	            ["path"] = path,
186	            ["exists"] = false,
187	            ["hashField"] = "",
188	            ["hashMatches"] = null,
189	        };
190	
191	        if (string.IsNullOrWhiteSpace(path))
192	        {
193	            failures.Add(Failure("changedFiles.path", "missing", "changedFiles item has no path"));
194	            return entry;
195	        }
196	
197	        var full = Path.GetFullPath(Path.Combine(root, path));
198	        var insideRoot = full.Equals(root, StringComparison.OrdinalIgnoreCase)
199	            || full.StartsWith(root.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar)
200	                + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase);
201	        if (!insideRoot)
202	        {
203	            failures.Add(Failure(path, "outside-root", "changedFiles path escapes repository root"));
204	            return entry;
205	        }
206	
207	        var exists = File.Exists(full) || Directory.Exists(full);
208	        entry["exists"] = exists;
209	        if (!exists)
210	        {
211	            failures.Add(Failure(path, "missing-file", "changedFiles path does not exist"));
212	            return entry;
213	        }
214	
215	        var expectedHash = ReadString(item, "sha256");
216	        var hashField = "sha256";
217	        if (string.IsNullOrWhiteSpace(expectedHash))
218	        {
219	            expectedHash = ReadString(item, "hash");
220	            hashField = "hash";
221	        }
222	
223	        entry["hashField"] = string.IsNullOrWhiteSpace(expectedHash) ? "" : hashField;
224	        if (string.IsNullOrWhiteSpace(expectedHash))
225	        {
226	            failures.Add(Failure(path, "missing-hash", "changedFiles item lacks sha256/hash"));
227	            return entry;
228	        }
229	
230	        if (Directory.Exists(full))
231	        {
232	            failures.Add(Failure(path, "directory-hash-unsupported", "changedFiles hash can only be verified for files"));
233	            return entry;
234	        }
235	
236	        var actualHash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(full))).ToLowerInvariant();
237	        var normalizedExpected = expectedHash.Trim().ToLowerInvariant().Replace("sha256:", "");
238	        var matches = actualHash.Equals(normalizedExpected, StringComparison.OrdinalIgnoreCase);
239	        entry["actualSha256"] = actualHash;
240	        entry["hashMatches"] = matches;
241	        if (!matches)
242	            failures.Add(Failure(path, "hash-mismatch", "changedFiles hash does not match current file content"));
243	
244	        return entry;
245	    }
246	
247	    // 완료 상태의 handoff가 실제 verification 아티팩트를 가리키는지 확인한다.
248	    private static void CheckCompletionArtifacts(string root, JsonObject workstate, string diId, string status, JsonArray failures, JsonArray warnings)
249	    {
250	        if (!DoneStatuses.Contains(status)) return;
251	
252	        var changed = workstate["changedFiles"] as JsonArray;
253	        var verificationInChangedFiles = changed?.OfType<JsonObject>()
254	            .Select(o => ReadString(o, "path"))
255	            .Any(p => p.StartsWith("docs/verification/", StringComparison.OrdinalIgnoreCase)
256	                && File.Exists(Path.Combine(root, p))) == true;
257	
258	        var verificationById = false;
259	        var verificationDir = Path.Combine(root, "docs", "verification");
260	        if (!verificationInChangedFiles && Directory.Exists(verificationDir) && !string.IsNullOrWhiteSpace(diId))
261	        {
262	            var normalized = NormalizeId(diId);
263	            verificationById = Directory.EnumerateFiles(verificationDir, "*.md")
264	                .Any(path => NormalizeId(Path.GetFileNameWithoutExtension(path)).Contains(normalized));
265	        }
266	
267	        if (!verificationInChangedFiles && !verificationById)
268	            failures.Add(Failure(diId, "missing-verification", "done status requires an existing docs/verification artifact"));
269	        else if (!verificationInChangedFiles)
270	            warnings.Add(Warning(diId, "verification-not-in-changedFiles", "verification exists by id but is not listed in current changedFiles"));
271	    }
272	
273	    // WORKSTATE diId가 큐 파일에서 열린 상태인지 대조한다.
274	    private static void CheckQueueStatus(string root, string diId, string status, JsonArray failures, JsonArray warnings)
275	    {
276	        if (string.IsNullOrWhiteSpace(diId)) return;
277	
278	        var queueFiles = new[]
279	        {
280	            "docs/handoff/CODEX-QUEUE.md",
281	            "docs/handoff/SONNET-QUEUE.md",
282	        };
283	        var mentions = new JsonArray();
284	        foreach (var rel in queueFiles)
285	        {
286	            var full = Path.Combine(root, rel);
287	            if (!File.Exists(full)) continue;
288	            foreach (var line in File.ReadLines(full).Where(l => l.Contains(diId, StringComparison.OrdinalIgnoreCase)))
289	            {
290	                mentions.Add(new JsonObject
291	                {
292	                    ["queue"] = rel,
293	                    ["line"] = line.Trim(),
294	                });
295	                if (DoneStatuses.Contains(status) && IsOpenQueueLine(line))
296	                    failures.Add(Failure(rel, "queue-status-mismatch", $"{diId} is done in WORKSTATE but open in queue line"));
297	            }
298	        }
299	
300	        if (mentions.Count == 0)
301	            warnings.Add(Warning(diId, "queue-mention-missing", "diId is not mentioned in CODEX or SONNET queue"));
302	    }
303	
304	    // blocked 상태에 blockers[]가 없거나 비어 있으면 blockers-missing, done 상태에 blockers[]가 남으면 blockers-stale.
305	    private static void CheckBlockerConsistency(JsonObject workstate, string status, JsonArray failures)
306	    {
307	        var blockers = workstate["blockers"] as JsonArray;
308	        var hasBlockers = blockers is not null && blockers.Count > 0;
309	        var blocked = status.Contains("block", StringComparison.OrdinalIgnoreCase);
310	        if (blocked && !hasBlockers)
311	            failures.Add(Failure("blockers", "blockers-missing", "blocked status requires a non-empty blockers array"));
312	        if (!blocked && hasBlockers && DoneStatuses.Contains(status))
313	            failures.Add(Failure("blockers", "blockers-stale", "done status must not carry a non-empty blockers array"));
314	    }
315	
316	    // 큐 행이 아직 열린 상태를 뜻하는지 판정한다.
317	    private static bool IsOpenQueueLine(string line)
318	        => line.Contains("대기", StringComparison.Ordinal)
319	            || line.Contains("진행", StringComparison.Ordinal)
320	            || line.Contains("pending", StringComparison.OrdinalIgnoreCase)
321	            || line.Contains("in progress", StringComparison.OrdinalIgnoreCase);
322	
323	    // JSON 객체에서 문자열 속성을 안전하게 읽는다.
324	    private static string ReadString(JsonObject obj, string property)
325	        => obj[property]?.ToString() ?? "";
326	
327	    // 지시서 ID와 파일명을 비교하기 쉬운 영숫자 소문자로 정규화한다.
328	    private static string NormalizeId(string value)
329	        => new string(value.Where(char.IsLetterOrDigit).Select(char.ToLowerInvariant).ToArray());
